  ('heelevel3-1fb53453-moex-00184', 'heelevel3-1fb53453', 'heelevel3-1fb53453-moex-112-3082b5f1', 'sub-heelevel3-1fb53453-02', NULL, 'single_choice', '藥事法規定不具藥商資格販賣藥品者，處新臺幣3萬元以上200萬元以下罰鍰。甲於網路上販售從 國外買回的藥品，被查獲違反前述藥事法規定，其請求依據行政罰法第19條規定免予處罰，承辦 此案之公務人員應如何處理？', '["若甲販賣藥品之獲利低於3萬元，得免予處罰", "若甲為初次違規，得免予處罰", "若藥品尚未售出，得免予處罰", "甲之情形無法適用行政罰法第19條免予處罰之規定 31550、31650 32250、32950 33050 33850"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:32:29+00:00", "source_pdf_sha1": "35e987219517", "answer_pdf_sha1": "d76f1552cd83", "source_family": "moex-gov-tw", "moex": {"exam_code": "112090", "c": "330", "s": "0403", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "112", "exam_name": "112年公務人員高等考試三級考試暨普通考試", "original_question_number": 17, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "財經廉政"}'::jsonb, NULL),
  ('heelevel3-1fb53453-moex-00185', 'heelevel3-1fb53453', 'heelevel3-1fb53453-moex-112-3082b5f1', 'sub-heelevel3-1fb53453-02', NULL, 'single_choice', '甲積欠交通違規罰單新臺幣18,000元，主管機關經催繳後仍未繳納，移送行政執行。依行政執行 法之規定，下列敘述何者正確？', '["如甲於執行程序終結前死亡，未留有遺產，執行機關應向甲之繼承人為執行", "如甲於執行程序終結前繳清罰鍰，其應以聲明異議之方式請求終止執行", "如執行機關發現甲顯有財產卻故意不繳納，且已出境1次，得限制甲之住居", "如甲對於執行機關限制住居之命令不服，經聲明異議遭駁回後，得直接提起撤銷訴訟"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:32:29+00:00", "source_pdf_sha1": "35e987219517", "answer_pdf_sha1": "d76f1552cd83", "source_family": "moex-gov-tw", "moex": {"exam_code": "112090", "c": "330", "s": "0403", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "112", "exam_name": "112年公務人員高等考試三級考試暨普通考試", "original_question_number": 18, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "財經廉政"}'::jsonb, NULL),
  ('heelevel3-1fb53453-moex-00186', 'heelevel3-1fb53453', 'heelevel3-1fb53453-moex-112-3082b5f1', 'sub-heelevel3-1fb53453-02', NULL, 'single_choice', '依據政府資訊公開法，關於政府資訊公開，下列敘述何者錯誤？', '["政府資訊可由政府機關主動公開，亦得應人民申請被動公開", "申請政府資訊之公開，不以主張或維護法律上利益有必要為前提", "對於政府資訊公開申請之決定不服者，得依法提起行政救濟", "經申請公開之政府資訊涉及第三人權益，經其明確表示不同意公開時，政府機關應即作成不予 公開之決定"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:32:29+00:00", "source_pdf_sha1": "35e987219517", "answer_pdf_sha1": "d76f1552cd83", "source_family": "moex-gov-tw", "moex": {"exam_code": "112090", "c": "330", "s": "0403", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "112", "exam_name": "112年公務人員高等考試三級考試暨普通考試", "original_question_number": 19, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "財經廉政"}'::jsonb, NULL),
  ('heelevel3-1fb53453-moex-00187', 'heelevel3-1fb53453', 'heelevel3-1fb53453-moex-112-3082b5f1', 'sub-heelevel3-1fb53453-02', NULL, 'single_choice', '下列何者非訴願審理機關審理訴願案件應遵循之原則？', '["書面審查原則", "職權調查原則", "不利益變更禁止原則", "停止執行原則"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:32:29+00:00", "source_pdf_sha1": "35e987219517", "answer_pdf_sha1": "d76f1552cd83", "source_family": "moex-gov-tw", "moex": {"exam_code": "112090", "c": "330", "s": "0403", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "112", "exam_name": "112年公務人員高等考試三級考試暨普通考試", "original_question_number": 20, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "財經廉政"}'::jsonb, NULL),
  ('heelevel3-1fb53453-moex-00188', 'heelevel3-1fb53453', 'heelevel3-1fb53453-moex-112-3082b5f1', 'sub-heelevel3-1fb53453-02', NULL, 'single_choice', '軍校生甲，因行為失當，遭學校開除學籍。學校擬對甲求償已領取之公費，應循何種方式？', '["以行政處分令甲賠償", "直接依強制執行法聲請強制執行", "向行政法院提起一般給付之訴", "向民事法院提起訴訟"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:32:29+00:00", "source_pdf_sha1": "35e987219517", "answer_pdf_sha1": "d76f1552cd83", "source_family": "moex-gov-tw", "moex": {"exam_code": "112090", "c": "330", "s": "0403", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "112", "exam_name": "112年公務人員高等考試三級考試暨普通考試", "original_question_number": 21, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "財經廉政"}'::jsonb, NULL),
  ('heelevel3-1fb53453-moex-00189', 'heelevel3-1fb53453', 'heelevel3-1fb53453-moex-112-3082b5f1', 'sub-heelevel3-1fb53453-02', NULL, 'single_choice', '多數當事人關於訴訟標的之權利義務關係，在事實上或法律上有同一或同類原因時，有關訴訟程 序之敘述，下列何者錯誤？', '["可以成立共同訴訟，一同擔任原告或被告", "如果當事人分別起訴，法院得命其合併辯論及合併裁判", "共同訴訟之訴訟標的有合一確定必要時，共同訴訟人中一人不利於全體之行為，效力不及於全 體共同訴訟人", "共同訴訟之訴訟標的無論有無合一確定必要，當事人合意停止訴訟後，續行訴訟必須經全體同意"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:32:29+00:00", "source_pdf_sha1": "35e987219517", "answer_pdf_sha1": "d76f1552cd83", "source_family": "moex-gov-tw", "moex": {"exam_code": "112090", "c": "330", "s": "0403", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "112", "exam_name": "112年公務人員高等考試三級考試暨普通考試", "original_question_number": 22, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "財經廉政"}'::jsonb, NULL),
  ('heelevel3-1fb53453-moex-00190', 'heelevel3-1fb53453', 'heelevel3-1fb53453-moex-112-3082b5f1', 'sub-heelevel3-1fb53453-02', NULL, 'single_choice', '依行政訴訟法規定之都市計畫審查程序，行政法院審查認定都市計畫違法時，下列何者非判決主 文得宣告之內容？', '["都市計畫違法者，宣告無效或違法", "都市計畫發布後始發生違法原因者，應宣告自違法原因發生時起失效", "同一都市計畫中未經原告請求，而與原告請求宣告無效之部分具不可分關係，經法院審查認定 違法者，併宣告撤銷", "依法僅得為違法之宣告者，應宣告其違法"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:32:29+00:00", "source_pdf_sha1": "35e987219517", "answer_pdf_sha1": "d76f1552cd83", "source_family": "moex-gov-tw", "moex": {"exam_code": "112090", "c": "330", "s": "0403", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "112", "exam_name": "112年公務人員高等考試三級考試暨普通考試", "original_question_number": 23, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "財經廉政"}'::jsonb, NULL),
  ('heelevel3-1fb53453-moex-00191', 'heelevel3-1fb53453', 'heelevel3-1fb53453-moex-112-3082b5f1', 'sub-heelevel3-1fb53453-02', NULL, 'single_choice', '某市政府自行興建設置之公立醫院委託私立醫學院經營，因原先所設置之手扶梯未定期保養而故 障，導致病患摔傷。下列敘述何者正確？', '["公共設施委託私人管理，因管理欠缺致人民身體受損害者，負國家賠償責任", "私立醫學院與病患間雖係私法關係，仍不得依民法向醫院求償", "委託屬公法關係，故病患不得依民法向醫院求償", "如病患為外國人者，則無法依國家賠償法求償"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:32:29+00:00", "source_pdf_sha1": "35e987219517", "answer_pdf_sha1": "d76f1552cd83", "source_family": "moex-gov-tw", "moex": {"exam_code": "112090", "c": "330", "s": "0403", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "112", "exam_name": "112年公務人員高等考試三級考試暨普通考試", "original_question_number": 24, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "財經廉政"}'::jsonb, NULL),
  ('heelevel3-1fb53453-moex-00192', 'heelevel3-1fb53453', 'heelevel3-1fb53453-moex-112-3082b5f1', 'sub-heelevel3-1fb53453-02', NULL, 'single_choice', '下列何者非屬政府應給予損失補償之適例？', '["公務員死亡後，所屬機關收回配住之宿舍", "警察依法追捕逃犯，遭逃犯衝撞警車，不慎導致路人甲受重傷", "消防隊為進入火場救火，移除窄巷內之機車，致機車受損", "主管機關就都市計畫道路用地，在徵收之前埋設地下公用管線"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:32:29+00:00", "source_pdf_sha1": "35e987219517", "answer_pdf_sha1": "d76f1552cd83", "source_family": "moex-gov-tw", "moex": {"exam_code": "112090", "c": "330", "s": "0403", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "112", "exam_name": "112年公務人員高等考試三級考試暨普通考試", "original_question_number": 25, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "財經廉政"}'::jsonb, NULL),
  ('heelevel3-1fb53453-moex-00193', 'heelevel3-1fb53453', 'heelevel3-1fb53453-moex-111-0b2477b6', 'sub-heelevel3-1fb53453-03', NULL, 'essay', '請說明什麼是系統減敏法（systematicdesensitization）及其作用為何？如
